package dev.codedefense.application;

import dev.codedefense.ai.JdkProcessExecutor;import dev.codedefense.change.*;import dev.codedefense.cli.ExitCodes;import dev.codedefense.domain.*;import dev.codedefense.passport.*;import dev.codedefense.terminal.ConfirmationPrompt;import java.io.PrintWriter;import java.nio.file.Path;import java.time.Clock;import java.util.*;import java.util.function.Supplier;
public final class RetryChangeDefenseUseCase implements RetryChangeDefenseRunner {private final ChangePassportStore store;private final GitChangeSource source;private final GitChangeDefenseRunner runner;
 public RetryChangeDefenseUseCase(ChangePassportStore store,GitChangeSource source,GitChangeDefenseRunner runner){this.store=Objects.requireNonNull(store);this.source=Objects.requireNonNull(source);this.runner=Objects.requireNonNull(runner);}
 public static RetryChangeDefenseUseCase production(Supplier<ConfirmationPrompt> confirmation){var store=new FileSystemChangePassportStore(ChangePassportPaths.defaults(),new MarkdownChangePassportRenderer(),Clock.systemUTC());var source=new GitCliChangeSource(new JdkProcessExecutor());return new RetryChangeDefenseUseCase(store,source,DefaultGitChangeDefenseRunner.production(confirmation));}
 @Override public int retry(String rawId,Path repository,boolean dryRun,boolean yes,PrintWriter out,PrintWriter err){PassportAttemptId id;try{id=new PassportAttemptId(rawId);}catch(IllegalArgumentException e){err.println("The Passport attempt ID is invalid.");return ExitCodes.INVALID_USAGE;}var stored=store.list(50).stream().filter(v->v.receipt().attemptId().equals(id)).findFirst();if(stored.isEmpty()){err.println("No matching Passport attempt was found.");return ExitCodes.NO_SUPPORTED_SOURCE_FILES;}var receipt=stored.orElseThrow().receipt();ChangeSelector selector=switch(receipt.changeKind()){case STAGED->new StagedSelector();case COMMIT->new CommitSelector(receipt.sourceIdentity());case RANGE->new RangeSelector(receipt.baseCommit(),receipt.sourceIdentity());};try{var current=source.captureIdentity(repository,selector);if(!current.diffFingerprint().equals(receipt.diffFingerprint())){err.println("The selected Git change has expired; retry was not started.");return ExitCodes.GIT_EXECUTION_FAILED;}}catch(GitChangeException e){err.println("The selected Git change is unavailable; retry was not started.");return ExitCodes.GIT_EXECUTION_FAILED;}out.println("Re-defense of attempt "+receipt.attemptNumber()+" uses all three categories.");return runner.run(repository,selector,receipt.focus(),dryRun,yes,out,err);}}
